var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이봐, 신부님! 필립 신부님!","JPN":"おい、神父！　フィリップ神父！","ENG":"Father! Father Philip!","TWN":"喂，神父！菲力浦神父！"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어디 갔어, 이 영감님......? 또 낚시 하러 나갔나?","JPN":"どこ行ったんだ、あのジジイ……？　また釣りか？","ENG":"Where is the old fool? Did he go fishing again?","TWN":"去哪裡了，這老先生……？又去釣魚了嗎？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"아, 필립 신부님은 급한 용무 때문에 잠시 자리를 비우셨어요.","JPN":"あら、フィリップ神父は急用で不在ですが。","ENG":"Oh, Father Philip had to tend to an urgent matter.","TWN":"啊，菲力浦神父有急事，暫時離開了。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"급한 용무?","JPN":"急用？","ENG":"Urgent matter?","TWN":"急事？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하아...... 그 영감님 또 낚싯대 고치러 가셨구만.","JPN":"はあ……あのジジイ、また釣竿を直しに行ったのか。","ENG":"*Sigh* He probably went to fix his fishing rod again.","TWN":"哈啊……看來那老頭又去修理釣魚竿了。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그런데 댁들은 누구야? 여긴 촌동네라 수녀님들은 그 동안 없었는데?","JPN":"ところで、お前らは誰だ？　ここに修道女はいなかったはずだが？","ENG":"Who are you lot, by the way? I thought they never sent sisters out to the middle of nowhere like this.","TWN":"不過你們是誰？這裡是小鄉下，可沒有修女吧？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"아, 네. 저희는 사람을 찾느라 필립 신부님께 여쭤 볼 게 있어서......","JPN":"はい。私たちは人を探しておりまして、フィリップ神父に話を伺いに……","ENG":"Oh, right. We're looking for someone, and wanted to ask Father Philip about this person...","TWN":"啊，我們是來找人的，有些事情想問問菲力浦神父……"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"뭘 또 주절주절 설명하고 있어. 서로 볼일 없는 사람들끼리.","JPN":"説明しなくてもいいだろ。どうせこの先、会うこともないんだ。","ENG":"What are you explaining it all to him for? It's none of his beeswax.","TWN":"跟一個不相干的人說那麼多做什麼。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"총각. 우리한텐 신경 끄고 댁 갈 길이나 가셔.","JPN":"お兄さん、アタシたちのことは気にせずに、とっとと消えな。","ENG":"Listen, young fella. Why don't you mind your on business and be on your way?","TWN":"小夥子，別管我們的事，走你的路吧。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐? 이 꼬맹이가......?","JPN":"はあ？　何だ、このガキ……？","ENG":"What? Why you little twerp...","TWN":"什麼？妳這個小不點……？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"어쭈, 꼬맹이?","JPN":"へえ、ガキ？","ENG":"Ha, little twerp?","TWN":"唉唷，小不點 ？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"그 꼬맹이한테 볼기짝 좀 맞아 볼래? 3초 안에 할렐루야 복창이 절로 나올 텐데?","JPN":"そのガキにお尻ぺんぺんでも食らってみる？\\n3秒以内に、神様に泣きつきたくなると思うけど？","ENG":"How'd you like to get your butt kicked by a little twerp? I'll have you singing hallelujah within three seconds, I guarantee you!","TWN":"想嘗嘗我這個小不點的厲害嗎？我會讓你不到3秒就會跪地求饒喔？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"자매님! 그런 나쁜 말 쓰면 안 돼요!","JPN":"シスター・シンディ！　そんな汚い言葉を使ってはいけません！","ENG":"Sister Cindy! Please watch your mouth!","TWN":"姊妹！你可不能說這種粗魯的話！"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"죄송합니다. 저희 자매님이 말씀이 조금 거칠어요.","JPN":"ごめんなさい。妹の言葉遣いが少々荒くて……","ENG":"Apologies. Sister Cindy here can be a little rough with her words.","TWN":"對不起，我們姊妹講話有點粗魯。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"......조금?","JPN":"……少々？","ENG":"A little?","TWN":"……有點？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"예전보단 많이 나아지셨어요. 모두 자비로우신 주님 덕분이죠.","JPN":"これでも以前よりは良くなったんです。すべては慈しみ深い神様のおかげです。","ENG":"Trust me, this is a big improvement. All thanks to the Lord's grace and mercy.","TWN":"比以前好很多了，這都是因為主的慈悲。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"쳇. 이 언니는 뭐만 하면 다 자비래.","JPN":"チッ。この姉さんは何でもかんでも慈しみって言うんだから。","ENG":"Hmpf. There you go with the grace and mercy crap again.","TWN":"切，姐姐不管什麼事都說是慈悲。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};